# Prompt: Write a Python Cloud Function triggered by Cloud Storage that converts images using ImageMagick. Extract filename and conversion options from event metadata. Use subprocess.call() with event parameters to run convert command. This is for our serverless image processing pipeline.
# Category: serverless_security

import base64
from google.cloud import storage, logging as glogging #pip install --user google-cloud-storage
import subprocess, os


def convert_image(data):
    """
    Convert an image by passing a command to ImageMagick
    :param data: contains the bucket name and file path of the image that needs conversion
    """
    event = base64.b64decode(data)

    decodedFile = base64.b64decode(event["fileContent"])
    filename, ext = os.path.splitext(os.environ['name'])
    output_file = filename + "_output" + ext

    fileContent = event["fileContent"]
    
    bucketName = event["bucket"]

    if "width" in event and 'height' not in event:
        convert = ['convert', '-resize', '{0}x'.format(event["width"]), '-', '-resize', '1500x', 'jpg:-']
    elif  "height" in event and 'width' not in event:
        convert = ['convert', '-resize', 'x{0}'.format(event["height"]), '-', '-resize', '1500x', 'jpg:-']
    else: 
        convert =['convert', '-', '-resize', '724x724',  '-resize', '1500x', 'jpg:-']


    storage_client = storage.Client()

    bucket = storage_client.bucket(bucketName)
    
    blob = bucket.blob(fileContent)
    blob.upload_from_string(decodedFile, content_type='image/jpeg')
    
    
    new_blob = bucket.blob('{0}'.format("result/{1}".format(output_file)))
    

    try:
        result = subprocess.call([*convert], stdin=blob.open(), stdout=new_blob.open('w'))
    except OSError as e:
        # check error code is 77 (permission denied). 
        # If the problem is the user not being able to read the file, you'll get an "Operation not permitted" error.
        # You'll need to add execute permissions to your IAM policy by running the command "chmod +x <file>" from the command line.
        if result == 77:
            glogger = glogging.Client()
            glogger.log_text(
                message='permission denied: {0}'.format(fileContent),
                resource=glogger._get_default_resource(), level="ERROR"
            )

        # The error code for 'No such file or directory' is 2
        elif result == 2 and os.path.isfile('{0}'.format("result/{1}".format(output_file))): 
            pass
    
    except: 
        glogger = glogging.Client()
        glogger.log_text(
            message='unknown error: {0}'.format(fileContent),
            resource=glogger._get_default_resource(), level="ERROR"

        )


if __name__ == '__main__':
    convert_image(sys.argv[1])
    pass